mapper.select:
SELECT doc_id, user_id, knowledge_base_id, title, content, type, source, tags,
       vector_id, chunk_index, chunk_size, chunking_strategy, chunk_count,
       status, create_time, update_time, deleted
FROM knowledge_document
WHERE deleted = 0

    AND knowledge_base_id = #{knowledgeBaseId}


    AND status = #{status}


    AND title LIKE CONCAT('%', #{title}, '%')


    AND type = #{type}


    AND user_id = #{userId}

ORDER BY create_time DESC
